namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 16;
static constexpr uint32_t HARD_CAP_ELEMS = 4096;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed2dAsymmetricInputAsymmetricKernelStridedGroupedPaddedDilatedCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const uint32_t N   = x_shape->GetOriginShape().GetDim(0);
    const uint32_t Cin = x_shape->GetOriginShape().GetDim(1);
    const uint32_t H   = x_shape->GetOriginShape().GetDim(2);
    const uint32_t W   = x_shape->GetOriginShape().GetDim(3);

    const uint32_t Cout = w_shape->GetOriginShape().GetDim(1);
    const uint32_t kH   = w_shape->GetOriginShape().GetDim(2);
    const uint32_t kW   = w_shape->GetOriginShape().GetDim(3);
    const uint32_t groups = 4;  // fixed from architecture

    // Convolution parameters (fixed for this architecture)
    const uint32_t strideH = 2, strideW = 3;
    const uint32_t padH = 1, padW = 2;
    const uint32_t dilH = 2, dilW = 1;
    const uint32_t H_out = (H - 1) * strideH - 2 * padH + dilH * (kH - 1) + 1;
    const uint32_t W_out = (W - 1) * strideW - 2 * padW + dilW * (kW - 1) + 1;

    uint32_t totalLength = N * Cout * H_out * W_out;

    // Tiling
    uint32_t maxTile = UB_BUDGET_BYTES / sizeof(float);
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);
    uint32_t tileLen = (totalLength < maxTile) ? AlignDown(totalLength, ALIGN_ELEMS) : maxTile;
    if (tileLen == 0) tileLen = totalLength;

    uint32_t numTiles = (tileLen == 0) ? 1 : CeilDiv(totalLength, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_N(N);
    tiling.set_C_out(Cout);
    tiling.set_H_out(H_out);
    tiling.set_W_out(W_out);
    tiling.set_C_in(Cin);
    tiling.set_H_in(H);
    tiling.set_W_in(W);
    tiling.set_kH(kH);
    tiling.set_kW(kW);
    tiling.set_groups(groups);
    tiling.set_strideH(strideH);
    tiling.set_strideW(strideW);
    tiling.set_padH(padH);
    tiling.set_padW(padW);
    tiling.set_dilH(dilH);
    tiling.set_dilW(dilW);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

